class AuthorizationService:
    """
    Core authorization logic that processes check requests.
    This is separated from the gRPC service for testability.
    """

    def __init__(self, policy: AuthorizationPolicy = None):
        self.policy = policy or AuthorizationPolicy()

    def check(self, method: str, path: str, headers: Dict[str, str],
              source_address: str = "", body: str = "") -> Dict:
        """
        Main authorization check.

        Returns a dict with:
            - allowed: bool
            - status_code: int (HTTP status code)
            - message: str
            - response_headers: dict of headers to add to response
            - request_headers: dict of headers to add to upstream request
        """
        result = {
            "allowed": False,
            "status_code": 401,
            "message": "",
            "response_headers": {},
            "request_headers": {},
            "headers_to_remove": [],
        }

        logger.info(f"Auth check: method={method}, path={path}, source={source_address}")

        # Check if path is public
        if self.policy.is_public_path(path):
            result["allowed"] = True
            result["status_code"] = 200
            result["request_headers"]["x-auth-status"] = "public"
            logger.info(f"Public path accessed: {path}")
            return result

        # Extract authentication credentials
        service_name = None
        auth_method = None

        # Check for API key in header
        api_key = headers.get("x-api-key", "")
        if api_key:
            service_name = self.policy.validate_api_key(api_key)
            if service_name:
                auth_method = "api-key"
            else:
                result["message"] = "Invalid API key"
                result["status_code"] = 401
                result["response_headers"]["x-auth-error"] = "invalid-api-key"
                logger.warning(f"Invalid API key from {source_address}")
                return result

        # Check for Bearer token
        if not service_name:
            auth_header = headers.get("authorization", "")
            if auth_header.startswith("Bearer "):
                token = auth_header[7:]
                token_payload = self.policy.validate_bearer_token(token)
                if token_payload:
                    service_name = token_payload.get("sub", "unknown")
                    auth_method = "bearer-token"
                    # Add token claims as headers for upstream
                    result["request_headers"]["x-auth-user-id"] = token_payload.get("sub", "")
                    result["request_headers"]["x-auth-roles"] = ",".join(
                        token_payload.get("roles", [])
                    )
                else:
                    result["message"] = "Invalid or expired bearer token"
                    result["status_code"] = 401
                    result["response_headers"]["x-auth-error"] = "invalid-token"
                    logger.warning(f"Invalid bearer token from {source_address}")
                    return result

        # Check for custom auth header
        if not service_name:
            custom_auth = headers.get("x-custom-auth", "")
            if custom_auth:
                # Custom authentication logic
                try:
                    auth_data = json.loads(custom_auth)
                    if "service" in auth_data and "signature" in auth_data:
                        # Verify custom signature
                        expected_sig = hmac.new(
                            self.policy.jwt_secret.encode(),
                            auth_data["service"].encode(),
                            hashlib.sha256
                        ).hexdigest()
                        if hmac.compare_digest(expected_sig, auth_data["signature"]):
                            service_name = auth_data["service"]
                            auth_method = "custom-auth"
                        else:
                            result["message"] = "Invalid custom auth signature"
                            result["status_code"] = 401
                            return result
                except (json.JSONDecodeError, KeyError):
                    result["message"] = "Malformed custom auth header"
                    result["status_code"] = 400
                    return result

        # No authentication provided
        if not service_name:
            result["message"] = "No authentication credentials provided"
            result["status_code"] = 401
            result["response_headers"]["www-authenticate"] = 'Bearer realm="envoy-ext-authz"'
            logger.warning(f"No auth credentials from {source_address} for {path}")
            return result

        # Check rate limiting
        if not self.policy.check_rate_limit(service_name):
            result["message"] = "Rate limit exceeded"
            result["status_code"] = 429
            result["response_headers"]["retry-after"] = str(self.policy.rate_limit_window)
            result["response_headers"]["x-ratelimit-limit"] = str(
                self.policy.rate_limit_max_requests
            )
            logger.warning(f"Rate limit exceeded for {service_name}")
            return result

        # Check RBAC
        if not self.policy.check_rbac(service_name, path, method):
            result["message"] = f"Service '{service_name}' not authorized for {method} {path}"
            result["status_code"] = 403
            result["response_headers"]["x-auth-error"] = "forbidden"
            logger.warning(
                f"RBAC denied: {service_name} attempted {method} {path}"
            )
            return result

        # Check required headers
        missing_headers = self.policy.check_required_headers(path, headers)
        if missing_headers:
            result["message"] = f"Missing required headers: {', '.join(missing_headers)}"
            result["status_code"] = 400
            result["response_headers"]["x-auth-error"] = "missing-headers"
            return result

        # Check custom header validations
        if "x-request-id" in headers:
            request_id = headers["x-request-id"]
            if len(request_id) > 128:
                result["message"] = "x-request-id too long"
                result["status_code"] = 400
                return result
            result["request_headers"]["x-request-id"] = request_id

        # Authorization granted
        result["allowed"] = True
        result["status_code"] = 200
        result["request_headers"]["x-auth-service"] = service_name
        result["request_headers"]["x-auth-method"] = auth_method
        result["request_headers"]["x-auth-timestamp"] = str(int(time.time()))
        # Remove the original auth headers before forwarding upstream
        result["headers_to_remove"] = ["x-api-key", "x-custom-auth"]

        logger.info(
            f"Auth granted: service={service_name}, method={auth_method}, "
            f"request={method} {path}"
        )
        return result


