if PROTOS_AVAILABLE:
    class ExtAuthzServicer(external_auth_pb2_grpc.AuthorizationServicer):
        """
        gRPC servicer implementing the Envoy ext_authz Authorization service.
        Uses the generated proto files from envoy-data-plane package.
        """

        def __init__(self, auth_service: AuthorizationService = None):
            self.auth_service = auth_service or AuthorizationService()

        def Check(self, request, context):
            """Handle authorization check requests from Envoy."""
            try:
                # Extract request attributes
                http_request = request.attributes.request.http
                method = http_request.method
                path = http_request.path
                host = http_request.host
                headers = dict(http_request.headers)
                body = http_request.body
                protocol = http_request.protocol

                # Extract source address
                source = request.attributes.source
                source_address = ""
                if source.HasField("address") and source.address.HasField("socket_address"):
                    sa = source.address.socket_address
                    source_address = f"{sa.address}:{sa.port_value}"

                # Perform authorization check
                auth_result = self.auth_service.check(
                    method=method,
                    path=path,
                    headers=headers,
                    source_address=source_address,
                    body=body,
                )

                # Build the CheckResponse
                response = external_auth_pb2.CheckResponse()

                if auth_result["allowed"]:
                    # Build OK response
                    response.status.CopyFrom(
                        status_pb2.Status(code=code_pb2.OK)
                    )

                    ok_response = external_auth_pb2.OkHttpResponse()

                    # Add headers to forward upstream
                    for key, value in auth_result.get("request_headers", {}).items():
                        header_value = base_pb2.HeaderValueOption(
                            header=base_pb2.HeaderValue(key=key, value=value),
                            append=False,
                        )
                        ok_response.headers.append(header_value)

                    # Set headers to remove
                    for header_name in auth_result.get("headers_to_remove", []):
                        ok_response.headers_to_remove.append(header_name)

                    response.ok_response.CopyFrom(ok_response)

                else:
                    # Build denied response
                    grpc_code = code_pb2.UNAUTHENTICATED
                    if auth_result["status_code"] == 403:
                        grpc_code = code_pb2.PERMISSION_DENIED

                    response.status.CopyFrom(
                        status_pb2.Status(
                            code=grpc_code,
                            message=auth_result["message"],
                        )
                    )

                    # Map HTTP status codes
                    http_code_map = {
                        400: http_status_pb2.BadRequest,
                        401: http_status_pb2.Unauthorized,
                        403: http_status_pb2.Forbidden,
                        429: http_status_pb2.TooManyRequests,
                        503: http_status_pb2.ServiceUnavailable,
                    }

                    denied_response = external_auth_pb2.DeniedHttpResponse()
                    denied_response.status.code = http_code_map.get(
                        auth_result["status_code"],
                        http_status_pb2.Unauthorized,
                    )

                    # Add response headers
                    for key, value in auth_result.get("response_headers", {}).items():
                        header_value = base_pb2.HeaderValueOption(
                            header=base_pb2.HeaderValue(key=key, value=value),
                            append=False,
                        )
                        denied_response.headers.append(header_value)

                    # Set response body
                    denied_response.body = json.dumps({
                        "error": auth_result["message"],
                        "status": auth_result["status_code"],
                    })

                    response.denied_response.CopyFrom(denied_response)

                return response

            except Exception as e:
                logger.error(f"Error processing auth check: {e}", exc_info=True)
                # Return a deny response on error
                response = external_auth_pb2.CheckResponse()
                response.status.CopyFrom(
                    status_pb2.Status(
                        code=code_pb2.INTERNAL,
                        message="Internal authorization error",
                    )
                )
                denied_response = external_auth_pb2.DeniedHttpResponse()
                denied_response.status.code = http_status_pb2.ServiceUnavailable
                denied_response.body = json.dumps({
                    "error": "Internal authorization service error",
                    "status": 503,
                })
                response.denied_response.CopyFrom(denied_response)
                return response


