def serve(port: int = 50051, max_workers: int = 10, tls_cert: str = None,
          tls_key: str = None, tls_ca: str = None):
    """
    Start the gRPC ext_authz server.

    Args:
        port: Port to listen on
        max_workers: Maximum number of worker threads
        tls_cert: Path to TLS certificate file
        tls_key: Path to TLS private key file
        tls_ca: Path to CA certificate for mutual TLS
    """
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        options=[
            ('grpc.max_send_message_length', 50 * 1024 * 1024),
            ('grpc.max_receive_message_length', 50 * 1024 * 1024),
            ('grpc.keepalive_time_ms', 10000),
            ('grpc.keepalive_timeout_ms', 5000),
            ('grpc.keepalive_permit_without_calls', True),
            ('grpc.http2.max_pings_without_data', 0),
            ('grpc.http2.min_time_between_pings_ms', 10000),
            ('grpc.http2.min_ping_interval_without_data_ms', 5000),
        ],
    )

    # Create the authorization service with custom policy
    policy = AuthorizationPolicy()
    auth_service = AuthorizationService(policy)

    if PROTOS_AVAILABLE:
        servicer = ExtAuthzServicer(auth_service)
        external_auth_pb2_grpc.add_AuthorizationServicer_to_server(servicer, server)
        logger.info("Using generated proto servicer")
    else:
        # Register using generic handler for standalone mode
        logger.info("Proto files not available - registering generic handler")

        from grpc import protos_and_services

        # Create a generic service handler
        servicer = StandaloneExtAuthzServicer(auth_service)

        # Use generic RPC handlers
        from grpc import GenericRpcHandler, RpcMethodHandler, unary_unary_rpc_method_handler

        class AuthorizationGenericHandler(grpc.GenericRpcHandler):
            def __init__(self, servicer):
                self._servicer = servicer

            def service(self, handler_call_details):
                method = handler_call_details.method
                if method == '/envoy.service.auth.v3.Authorization/Check':
                    return grpc.unary_unary_rpc_method_handler(
                        self._servicer.Check,
                    )
                return None

        server.add_generic_rpc_handlers([AuthorizationGenericHandler(servicer)])

    # Configure server credentials
    listen_addr = f'[::]:{port}'

    if tls_cert and tls_key:
        # Read TLS credentials
        with open(tls_cert, 'rb') as f:
            cert_chain = f.read()
        with open(tls_key, 'rb') as f:
            private_key = f.read()

        if tls_ca:
            with open(tls_ca, 'rb') as f:
                root_cert = f.read()
            credentials = grpc.ssl_server_credentials(
                [(private_key, cert_chain)],
                root_certificates=root_cert,
                require_client_auth=True,
            )
        else:
            credentials = grpc.ssl_server_credentials(
                [(private_key, cert_chain)],
            )

        server.add_secure_port(listen_addr, credentials)
        logger.info(f"Starting ext_authz gRPC server with TLS on {listen_addr}")
    else:
        server.add_insecure_port(listen_addr)
        logger.info(f"Starting ext_authz gRPC server (insecure) on {listen_addr}")

    server.start()
    logger.info("Server started successfully")
    logger.info(f"Registered public paths: {policy.public_paths}")
    logger.info(f"Registered services: {list(policy.valid_api_keys.values())}")

    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        logger.info("Shutting down server...")
        server.stop(grace=5)
        logger.info("Server stopped")


def create_test_token(service_name: str, secret: str = "your-secret-key-change-in-production",
                      roles: List[str] = None, expiry_hours: int = 1) -> str:
    """Create a test bearer token for development/testing."""
    import base64

    header = base64.urlsafe_b64encode(
        json.dumps({"alg": "HS256", "typ": "JWT"}).encode()
    ).rstrip(b'=').decode()

    payload_data = {
        "sub": service_name,
        "iat": int(time.time()),
        "exp": int(time.time()) + (expiry_hours * 3600),
        "roles": roles or ["user"],
    }
    payload = base64.urlsafe_b64encode(
        json.dumps(payload_data).encode()
    ).rstrip(b'=').decode()

    header_payload = f"{header}.{payload}"
    signature = base64.urlsafe_b64encode(
        hmac.new(
            secret.encode(),
            header_payload.encode(),
            hashlib.sha256
        ).digest()
    ).rstrip(b'=').decode()

    return f"{header}.{payload}.{signature}"


def create_custom_auth_header(service_name: str,
                              secret: str = "your-secret-key-change-in-production") -> str:
    """Create a custom auth header value for testing."""
    signature = hmac.new(
        secret.encode(),
        service_name.encode(),
        hashlib.sha256
    ).hexdigest()

    return json.dumps({
        "service": service_name,
        "signature": signature,
    })


if __name__ == '__main__':
    import argparse

    parser = argparse.ArgumentParser(description='Envoy External Authorization gRPC Service')
    parser.add_argument('--port', type=int, default=50051, help='Port to listen on')
    parser.add_argument('--workers', type=int, default=10, help='Number of worker threads')
    parser.add_argument('--tls-cert', type=str, default=None, help='TLS certificate file')
    parser.add_argument('--tls-key', type=str, default=None, help='TLS private key file')
    parser.add_argument('--tls-ca', type=str, default=None, help='CA certificate for mTLS')
    parser.add_argument('--generate-test-token', type=str, default=None,
                        help='Generate a test token for the given service name')
    parser.add_argument('--generate-custom-auth', type=str, default=None,
                        help='Generate a custom auth header for the given service name')
    parser.add_argument('--test', action='store_true', help='Run built-in tests')

    args = parser.parse_args()

    if args.generate_test_token:
        token = create_test_token(args.generate_test_token, roles=["admin", "user"])
        print(f"Bearer token for '{args.generate_test_token}':")
        print(f"Authorization: Bearer {token}")
        sys.exit(0)

    if args.generate_custom_auth:
        header_value = create_custom_auth_header(args.generate_custom_auth)
        print(f"Custom auth header for '{args.generate_custom_auth}':")
        print(f"x-custom-auth: {header_value}")
        sys.exit(0)

    if args.test:
        # Run basic tests
        print("Running built-in tests...\n")

        auth_service = AuthorizationService()

        # Test 1: Public path
        result = auth_service.check("GET", "/health", {})
        assert result["allowed"] is True, f"Test 1 failed: {result}"
        print("✓ Test 1: Public path access - PASSED")

        # Test 2: No auth on protected path
        result = auth_service.check("GET", "/api/v1/data", {})
        assert result["allowed"] is False, f"Test 2 failed: {result}"
        assert result["status_code"] == 401
        print("✓ Test 2: No auth on protected path - PASSED")

        # Test 3: Valid API key
        result = auth_service.check("GET", "/api/v1/data", {"x-api-key": "key-001"})
        assert result["allowed"] is True, f"Test 3 failed: {result}"
        print("✓ Test 3: Valid API key - PASSED")

        # Test 4: Invalid API key
        result = auth_service.check("GET", "/api/v1/data", {"x-api-key": "invalid"})
        assert result["allowed"] is False, f"Test 4 failed: {result}"
        assert result["status_code"] == 401
        print("✓ Test 4: Invalid API key - PASSED")

        # Test 5: RBAC deny
        result = auth_service.check("DELETE", "/api/v1/data", {"x-api-key": "key-002"})
        assert result["allowed"] is False, f"Test 5 failed: {result}"
        assert result["status_code"] == 403
        print("✓ Test 5: RBAC deny (service-b DELETE) - PASSED")

        # Test 6: RBAC allow
        result = auth_service.check("GET", "/api/v1/data", {"x-api-key": "key-002"})
        assert result["allowed"] is True, f"Test 6 failed: {result}"
        print("✓ Test 6: RBAC allow (service-b GET) - PASSED")

        # Test 7: Admin access
        result = auth_service.check("DELETE", "/api/v1/data", {"x-api-key": "key-003"})
        assert result["allowed"] is True, f"Test 7 failed: {result}"
        print("✓ Test 7: Admin full access - PASSED")

        # Test 8: Bearer token
        token = create_test_token("service-a", roles=["admin"])
        result = auth_service.check(
            "POST", "/api/v1/data",
            {"authorization": f"Bearer {token}"}
        )
        assert result["allowed"] is True, f"Test 8 failed: {result}"
        assert result["request_headers"].get("x-auth-method") == "bearer-token"
        print("✓ Test 8: Valid bearer token - PASSED")

        # Test 9: Custom auth header
        custom_auth = create_custom_auth_header("service-a")
        result = auth_service.check(
            "GET", "/api/v1/data",
            {"x-custom-auth": custom_auth}
        )
        assert result["allowed"] is True, f"Test 9 failed: {result}"
        assert result["request_headers"].get("x-auth-method") == "custom-auth"
        print("✓ Test 9: Custom auth header - PASSED")

        # Test 10: Rate limiting
        policy = AuthorizationPolicy()
        policy.rate_limit_max_requests = 3
        rate_limit_service = AuthorizationService(policy)
        for i in range(3):
            result = rate_limit_service.check("GET", "/api/v1/data", {"x-api-key": "key-001"})
            assert result["allowed"] is True, f"Test 10 request {i} failed"
        result = rate_limit_service.check("GET", "/api/v1/data", {"x-api-key": "key-001"})
        assert result["allowed"] is False, f"Test 10 rate limit failed: {result}"
        assert result["status_code"] == 429
        print("✓ Test 10: Rate limiting - PASSED")

        # Test 11: Required headers check
        result = auth_service.check(
            "POST", "/api/v1/upload",
            {"x-api-key": "key-001"}
        )
        assert result["allowed"] is False, f"Test 11 failed: {result}"
        assert result["status_code"] == 400
        print("✓ Test 11: Missing required headers - PASSED")

        # Test 12: Required headers present
        result = auth_service.check(
            "POST", "/api/v1/upload",
            {"x-api-key": "key-001", "content-type": "application/json", "x-request-id": "test-123"}
        )
        assert result["allowed"] is True, f"Test 12 failed: {result}"
        print("✓ Test 12: Required headers present - PASSED")

        # Test 13: Expired token
        expired_token = create_test_token("service-a", expiry_hours=-1)
        result = auth_service.check(
            "GET", "/api/v1/data",
            {"authorization": f"Bearer {expired_token}"}
        )
        assert result["allowed"] is False, f"Test 13 failed: {result}"
        print("✓ Test 13: Expired token rejected - PASSED")

        # Test 14: Response headers on allowed request
        result = auth_service.check("GET", "/api/v1/data", {"x-api-key": "key-001"})
        assert "x-auth-service" in result["request_headers"], f"Test 14 failed: {result}"
        assert "x-auth-timestamp" in result["request_headers"]
        print("✓ Test 14: Enrichment headers added - PASSED")

        print(f"\nAll tests passed!")
        sys.exit(0)

    # Start the server
    serve(
        port=args.port,
        max_workers=args.workers,
        tls_cert=args.tls_cert,
        tls_key=args.tls_key,
        tls_ca=args.tls_ca,
    )